#!/usr/bin/env python3
"""Readonly Trello pdf_to_excel OCR smoke runner.

This wrapper keeps delegation limited to the reviewed artifacts/scripts/pdf_to_excel_ocr.py
implementation while enforcing the evidence gates required for reviewable outcomes.
"""
from __future__ import annotations

import argparse
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Any, Dict, List, Optional, Tuple

DEFAULT_TIMEOUT_SECONDS = 900
STDIO_TAIL_LIMIT = 4000


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description=(
            "Run the reviewed pdf_to_excel_ocr.py delegate with Trello smoke metadata "
            "and enforce the repository's reviewable evidence contract."
        )
    )
    parser.add_argument("--input-dir", required=True, help="Directory containing candidate PDF files.")
    parser.add_argument(
        "--output-xlsx",
        required=True,
        help="Destination XLSX path for the extracted workbook (created if delegate succeeds).",
    )
    parser.add_argument(
        "--ocr",
        default="auto",
        help="OCR mode forwarded to the delegate (for example: auto/on/off depending on delegate support).",
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Request a delegate dry-run; wrapper will still execute the delegate but report partial outcome.",
    )
    parser.add_argument("--origin-id", help="External card or job identifier for traceability.")
    parser.add_argument("--title", help="Human-readable request title for the runtime summary.")
    parser.add_argument(
        "--description",
        help="Full request description retained verbatim for downstream evidence review",
    )
    parser.add_argument(
        "--labels",
        nargs="*",
        default=[],
        help="Optional list of governance labels associated with the request.",
    )
    parser.add_argument(
        "--delegate-script",
        help=(
            "Optional override path for the reviewed pdf_to_excel_ocr.py delegate. "
            "Defaults to the sibling script inside artifacts/scripts/."
        ),
    )
    parser.add_argument(
        "--timeout",
        type=int,
        default=DEFAULT_TIMEOUT_SECONDS,
        help="Maximum seconds to wait for the delegate before reporting a timeout failure.",
    )
    return parser.parse_args()


def resolve_delegate_script(delegate_override: Optional[str]) -> Path:
    if delegate_override:
        delegate_path = Path(delegate_override).expanduser().resolve()
    else:
        delegate_path = Path(__file__).resolve().parent / "pdf_to_excel_ocr.py"
    return delegate_path


def load_json_from_file(path: Path) -> Optional[Dict[str, Any]]:
    try:
        with path.open("r", encoding="utf-8") as handle:
            return json.load(handle)
    except FileNotFoundError:
        return None
    except json.JSONDecodeError:
        return None


def load_json_from_stdout(stdout_text: str) -> Optional[Dict[str, Any]]:
    text = stdout_text.strip()
    if not text:
        return None
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    for candidate in reversed(lines):
        try:
            return json.loads(candidate)
        except json.JSONDecodeError:
            continue
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        return None


def tail_text(value: str, limit: int = STDIO_TAIL_LIMIT) -> str:
    if len(value) <= limit:
        return value
    return value[-limit:]


def evaluate_outcome(
    report: Optional[Dict[str, Any]],
    args: argparse.Namespace,
    timed_out: bool,
    exit_code: Optional[int],
) -> Tuple[str, List[str], List[str]]:
    notes: List[str] = []
    gating_reasons: List[str] = []
    if timed_out:
        notes.append(
            "Delegate execution exceeded the configured timeout and was terminated before a report was produced."
        )
        return "failed", notes, gating_reasons
    if report is None:
        if exit_code == 0:
            notes.append(
                "Delegate exited with code 0 but did not emit a structured report; treating outcome as partial due to missing evidence."
            )
            return "partial", notes, gating_reasons
        notes.append("Delegate report was unavailable and exit code indicates failure.")
        return "failed", notes, gating_reasons

    delegate_status = (report.get("status") or "").strip().lower()
    total_files = report.get("total_files")
    dry_run_reported = bool(report.get("dry_run"))
    status_counter = report.get("status_counter") or {}
    excel_written = report.get("excel_written") is True
    output_exists = report.get("output_exists") is True
    output_size = report.get("output_size_bytes") or 0
    ocr_runtime_status = (report.get("ocr_runtime_status") or "").strip().lower()

    if delegate_status == "success":
        if dry_run_reported or args.dry_run:
            gating_reasons.append("Dry-run context prevents claiming a full success outcome.")
        if not isinstance(total_files, int) or total_files < 1:
            gating_reasons.append("Delegate did not confirm processing at least one PDF file.")
        if status_counter.get("failed"):
            gating_reasons.append("Delegate reported failed files in status_counter.failed.")
        if status_counter.get("partial"):
            gating_reasons.append("Delegate reported partial files in status_counter.partial.")
        if not excel_written:
            gating_reasons.append("Delegate did not attest to writing the XLSX output (excel_written=false).")
        if not output_exists:
            gating_reasons.append("Delegate did not confirm the XLSX file exists on disk.")
        if not isinstance(output_size, int) or output_size <= 0:
            gating_reasons.append("Delegate reported a non-positive XLSX size (output_size_bytes<=0).")
        if args.ocr in {"auto", "on"} and ocr_runtime_status in {"blocked", "partial"}:
            gating_reasons.append(
                "Delegate reported OCR runtime status '%s', which is insufficient for an auto/on OCR request."
                % ocr_runtime_status
            )
        if gating_reasons:
            notes.append(
                "Delegate returned success but reviewable success gates were not fully satisfied; reporting partial outcome."
            )
            return "partial", notes, gating_reasons
        notes.append("Delegate satisfied all success evidence gates.")
        return "success", notes, gating_reasons

    if delegate_status == "partial":
        delegate_message = report.get("message") or report.get("detail") or "Delegate reported partial progress."
        notes.append(delegate_message)
        limitations = report.get("limitations")
        if isinstance(limitations, list):
            notes.extend(str(item) for item in limitations if item)
        return "partial", notes, gating_reasons

    delegate_message = report.get("message") or "Delegate reported failure."
    notes.append(delegate_message)
    return "failed", notes, gating_reasons


def main() -> int:
    args = parse_args()
    input_dir = Path(args.input_dir).expanduser()
    output_xlsx = Path(args.output_xlsx).expanduser()
    output_xlsx.parent.mkdir(parents=True, exist_ok=True)

    delegate_script = resolve_delegate_script(args.delegate_script)
    if not delegate_script.is_file():
        payload = {
            "status": "failed",
            "error": f"Delegate script not found: {delegate_script}",
        }
        print(json.dumps(payload, indent=2, ensure_ascii=False))
        return 1

    if not input_dir.exists():
        payload = {
            "status": "failed",
            "error": f"Input directory does not exist: {input_dir}",
        }
        print(json.dumps(payload, indent=2, ensure_ascii=False))
        return 1

    timeout_seconds = max(int(args.timeout or DEFAULT_TIMEOUT_SECONDS), 1)
    report_path = output_xlsx.with_suffix(f"{output_xlsx.suffix}.report.json")
    if report_path.exists():
        report_path.unlink()

    delegate_cmd: List[str] = [
        sys.executable,
        str(delegate_script),
        "--input-dir",
        str(input_dir),
        "--output-xlsx",
        str(output_xlsx),
        "--ocr",
        str(args.ocr),
        "--report-json",
        str(report_path),
    ]
    if args.dry_run:
        delegate_cmd.append("--dry-run")

    delegate_stdout = ""
    delegate_stderr = ""
    delegate_exit_code: Optional[int] = None
    timed_out = False

    try:
        completed = subprocess.run(
            delegate_cmd,
            capture_output=True,
            text=True,
            env=os.environ.copy(),
            timeout=timeout_seconds,
            check=False,
        )
        delegate_exit_code = completed.returncode
        delegate_stdout = completed.stdout or ""
        delegate_stderr = completed.stderr or ""
    except subprocess.TimeoutExpired as exc:
        timed_out = True
        delegate_stdout = exc.stdout or ""
        delegate_stderr = exc.stderr or ""

    report_data = load_json_from_file(report_path)
    if report_data is None:
        report_data = load_json_from_stdout(delegate_stdout)

    status, notes, gating_reasons = evaluate_outcome(report_data, args, timed_out, delegate_exit_code)

    summary_payload: Dict[str, Any] = {
        "status": status,
        "request": {
            "title": args.title,
            "description": args.description,
            "origin_id": args.origin_id,
            "labels": args.labels,
            "input_dir": str(input_dir),
            "output_xlsx": str(output_xlsx),
            "ocr_mode": args.ocr,
            "dry_run": bool(args.dry_run),
            "readonly_semantics": (
                "Readonly Trello preview: no Trello writeback; local filesystem writes are allowed when dry_run is False."
            ),
        },
        "delegate": {
            "script": str(delegate_script),
            "command": delegate_cmd,
            "report_path": str(report_path),
            "exit_code": delegate_exit_code,
            "timed_out": timed_out,
            "report": report_data,
            "stdout_tail": tail_text(delegate_stdout),
            "stderr_tail": tail_text(delegate_stderr),
        },
        "outcome": {
            "notes": notes,
            "gating_reasons": gating_reasons,
        },
    }

    print(json.dumps(summary_payload, indent=2, ensure_ascii=False))
    return 0 if status in {"success", "partial"} else 1


if __name__ == "__main__":
    sys.exit(main())
